import binascii
import base64
from typing import Optional

hex_payload = ""

def decode_bytes(hex_payload: str) -> Optional[str]:
    """Decodes the hexadecimal payload into a readable UTF-8 string."""
    try:
        # 1. Convert hex to raw bytes (Success in previous step)
        byte_data = binascii.unhexlify(hex_payload)
        print("\n--- Step 1: Raw Bytes Successfully Generated ---")
        # print(byte_data) # Keep this line commented unless debugging byte values

        # 2. Attempt to decode bytes into a string (THE CRITICAL STEP)
        # 'errors="replace"' tells Python what to do if it hits an illegal character, 
        # preventing the program from crashing and allowing us to salvage partial data.
        decoded_text = byte_data.decode('utf-8', errors='replace')
        
        return decoded_text

    except binascii.Error as e:
        print(f"\n[ERROR] Failed during Hexadecimal decoding: {e}")
        # This means the input hex string is malformed (odd length, invalid characters).
        return None
    except UnicodeDecodeError as e:
        # This handles cases where the bytes are valid but not UTF-8.
        print(f"\n[WARN] Decoding failed with standard UTF-8. Error: {e}")
        return None

# Run the decoder
decoded_result = decode_bytes(hex_payload)


if decoded_result:
    # Print a truncated view to avoid massive console output, unless it's short enough.
    if len(decoded_result) > 500:
        print("\n========================================")
        print("DECODING SUCCESSFUL (TRUNCATED VIEW):")
        print(decoded_result[:500] + "\n[... Content truncated for readability ...]")
        print("========================================")
    else:
        print("\n========================================")
        print("DECODED CONTENT:")
        print(decoded_result)
        print("========================================")
